use std::rc::Rc; use std::cell::RefCell;impl Solution { pub fn flip_match_voyage(root: Option<Rc<RefCell<TreeNode>>>, voyage: Vec<i32>) -> Vec<i32> { let (mut black_idx, mut black_res) = (0, vec![]); if Self::black_dfs(&root, &voyage, &mut black_idx, &mut black_res) { black_res } else { vec![-1] } } fn black_dfs(node: &Option<Rc<RefCell<TreeNode>>>, voyage: &Vec<i32>, black_idx: &mut usize, black_res: &mut Vec<i32>) -> bool { if let Some(black_n) = node { let b_node = black_n.borrow(); if b_node.val != voyage[*black_idx] { return false; } *black_idx += 1; if b_node.left.is_some() && b_node.left.as_ref().unwrap().borrow().val != voyage[*black_idx] { black_res.push(b_node.val); return Self::black_dfs(&b_node.right, voyage, black_idx, black_res) && Self::black_dfs(&b_node.left, voyage, black_idx, black_res); } return Self::black_dfs(&b_node.left, voyage, black_idx, black_res) && Self::black_dfs(&b_node.right, voyage, black_idx, black_res); } true } }